import React, { useState, useEffect } from 'react';
import axios from 'axios';

const StockMovementForm = ({ refreshMovements, refreshProducts }) => {
    const [products, setProducts] = useState([]);
    const [movement, setMovement] = useState({
        produto: '',
        tipo_movimentacao: 'entrada',
        quantidade: '',
        motivo: ''
    });

    useEffect(() => {
        fetchProducts();
    }, []);

    const fetchProducts = async () => {
        try {
            const response = await axios.get('http://127.0.0.1:8000/api/produtos/');
            setProducts(response.data);
        } catch (error) {
            console.error("Erro ao buscar produtos:", error);
        }
    };

    const handleChange = (e) => {
        const { name, value } = e.target;
        setMovement({ ...movement, [name]: value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            await axios.post('http://127.0.0.1:8000/api/movimentacoes/', {
                produto: movement.produto,
                tipo_movimentacao: movement.tipo_movimentacao,
                quantidade: parseInt(movement.quantidade, 10),
                motivo: movement.motivo
            });

            refreshMovements();
            refreshProducts();
            setMovement({ produto: '', tipo_movimentacao: 'entrada', quantidade: '', motivo: '' });

        } catch (error) {
            console.error("Erro ao registrar movimentação:", error);
        }
    };

    return (
        <div>
            <form onSubmit={handleSubmit}>
                <select name="produto" value={movement.produto} onChange={handleChange} required>
                    <option value="">Selecione um Produto</option>
                    {products.map((product) => (
                        <option key={product.id} value={product.id}>
                            {product.nome}
                        </option>
                    ))}
                </select>

                <select name="tipo_movimentacao" value={movement.tipo_movimentacao} onChange={handleChange}>
                    <option value="entrada">Entrada</option>
                    <option value="saida">Saída</option>
                </select>

                <input type="number" name="quantidade" value={movement.quantidade} onChange={handleChange} placeholder="Quantidade" required />
                <input type="text" name="motivo" value={movement.motivo} onChange={handleChange} placeholder="Motivo" />

                <button type="submit">Registrar</button>
            </form>
        </div>
    );

    const StockMovementList = ({ movements, onEdit, onDelete }) => {
        return (
            <div>
                {movements.map((movement) => (
                    <div key={movement.id} style={{ margin: '10px', border: '1px solid #ccc', padding: '10px' }}>
                        <h3>Produto: {movement.produto.nome}</h3>
                        <p>Tipo de Movimentação: {movement.tipo_movimentacao}</p>
                        <p>Quantidade: {movement.quantidade}</p>
                        <p>Motivo: {movement.motivo}</p>
                        <p>Data: {new Date(movement.data).toLocaleDateString()}</p>
                        <button onClick={() => onEdit(movement)}>Editar</button>
                        <button onClick={() => onDelete(movement.id)}>Excluir</button>
                    </div>
                ))}
            </div>
        );
};
};

export default StockMovementForm;
